#!/usr/bin/env node
// scripts/audit-hero-library-origins.mjs
//
// Splits every hero-library.json entry into three buckets by URL
// pattern so Philip can see which images are safe (AI-generated by
// him via ChatGPT) vs which came from unknown sources (hash-named
// files that might be scraped from the web).
//
// Usage: node scripts/audit-hero-library-origins.mjs
//
// Output: console report + optional --json flag writes a machine
// readable audit to scripts/hero-library-audit.json.

import fs from "node:fs";
import path from "node:path";

const LIB_PATH = path.join(process.cwd(), "scripts", "hero-library.json");
const OUT_PATH = path.join(process.cwd(), "scripts", "hero-library-audit.json");

const lib = JSON.parse(fs.readFileSync(LIB_PATH, "utf8"));
const entries = Array.isArray(lib.entries) ? lib.entries : [];

// Classification rules:
//   • URL contains "ChatGPT" (case-insensitive) → AI-generated
//     (Philip's own prompts, output fully owned).
//   • URL contains a Supabase / ImageKit "migrated" path → likely
//     platform-hosted upload from an authenticated user (probably
//     safe but flag for verification).
//   • URL matches a bare hex/base64 hash filename (32+ chars) →
//     UNKNOWN provenance, most likely scraped from the web.
//   • Everything else → UNKNOWN.

const AI_PATTERNS = [
  /chatgpt/i,
  /midjourney/i,
  /dalle/i,
  /flux/i,
  /openai/i,
  /stable[-_]?diffusion/i
];

const UPLOAD_PATTERNS = [
  /supabase\.co\/storage/i,
  /\/migrated\//i,
  /\/product-images\//i
];

const HASH_PATTERN = /\/[a-f0-9]{16,}(?:\.[a-z]{3,4})(?:\?|$)/i;

const buckets = {
  ai_generated:    [],
  platform_upload: [],
  unknown_hash:    [],
  unknown_other:   []
};

function classify(url) {
  if (!url) return "unknown_other";
  if (AI_PATTERNS.some((r) => r.test(url))) return "ai_generated";
  if (UPLOAD_PATTERNS.some((r) => r.test(url))) return "platform_upload";
  if (HASH_PATTERN.test(url)) return "unknown_hash";
  return "unknown_other";
}

for (const entry of entries) {
  const bucket = classify(entry.image_url ?? "");
  buckets[bucket].push({
    id:                entry.id,
    url:               entry.image_url,
    subject:           entry.subject,
    sibling_group_id:  entry.sibling_group_id ?? null,
    posted_by:         entry.$posted_by ?? null
  });
}

// Sibling-group breakdown for the unknown_hash bucket — shows
// exactly which categories carry the copyright risk.
const riskByGroup = {};
for (const e of buckets.unknown_hash) {
  const g = e.sibling_group_id ?? "(no group)";
  riskByGroup[g] = (riskByGroup[g] ?? 0) + 1;
}
for (const e of buckets.unknown_other) {
  const g = e.sibling_group_id ?? "(no group)";
  riskByGroup[g] = (riskByGroup[g] ?? 0) + 1;
}

const total = entries.length;
const aiPct    = ((buckets.ai_generated.length    / total) * 100).toFixed(1);
const upPct    = ((buckets.platform_upload.length / total) * 100).toFixed(1);
const hashPct  = ((buckets.unknown_hash.length    / total) * 100).toFixed(1);
const otherPct = ((buckets.unknown_other.length   / total) * 100).toFixed(1);

// ─── Console report ─────────────────────────────────────────────
const bold  = (s) => `\x1b[1m${s}\x1b[0m`;
const green = (s) => `\x1b[32m${s}\x1b[0m`;
const yellow= (s) => `\x1b[33m${s}\x1b[0m`;
const red   = (s) => `\x1b[31m${s}\x1b[0m`;
const dim   = (s) => `\x1b[2m${s}\x1b[0m`;

console.log(`\n${bold("hero-library.json — provenance audit")}`);
console.log(dim(`  ${LIB_PATH}`));
console.log(dim(`  ${total} total entries`));
console.log("");
console.log(`  ${green("SAFE   AI-generated       ")}  ${bold(buckets.ai_generated.length.toString().padStart(4))} ${dim(`(${aiPct}%)`)}`);
console.log(`  ${green("SAFE   Platform upload    ")}  ${bold(buckets.platform_upload.length.toString().padStart(4))} ${dim(`(${upPct}%)`)}`);
console.log(`  ${red("RISK   Hash-named URL     ")}  ${bold(buckets.unknown_hash.length.toString().padStart(4))} ${dim(`(${hashPct}%)`)}`);
console.log(`  ${yellow("CHECK  Other unknown      ")}  ${bold(buckets.unknown_other.length.toString().padStart(4))} ${dim(`(${otherPct}%)`)}`);
console.log("");

const riskCount = buckets.unknown_hash.length + buckets.unknown_other.length;
if (riskCount > 0) {
  console.log(bold(`  ⚠  ${riskCount} entries need provenance verification.`));
  console.log(dim("     Regenerate via ChatGPT, license, or replace with trade submissions."));
  console.log("");
  console.log(bold("  Risk breakdown by sibling group:"));
  const rows = Object.entries(riskByGroup).sort((a,b) => b[1]-a[1]);
  for (const [group, count] of rows) {
    const bar = "█".repeat(Math.min(count, 40));
    console.log(`    ${count.toString().padStart(4)}  ${red(bar)} ${dim(group)}`);
  }
  console.log("");
}

// ─── JSON dump ──────────────────────────────────────────────────
if (process.argv.includes("--json")) {
  const audit = {
    generated_at: new Date().toISOString(),
    total,
    counts: {
      ai_generated:    buckets.ai_generated.length,
      platform_upload: buckets.platform_upload.length,
      unknown_hash:    buckets.unknown_hash.length,
      unknown_other:   buckets.unknown_other.length
    },
    risk_by_sibling_group: riskByGroup,
    entries: buckets
  };
  fs.writeFileSync(OUT_PATH, JSON.stringify(audit, null, 2));
  console.log(dim(`  wrote ${OUT_PATH}`));
  console.log("");
}
